import { getUpdates, sendMessage, sendTyping } from "./lib/telegram";
import { generateResponse } from "./lib/claude";
import {
  getLastOffset,
  setLastOffset,
  getHistory,
  appendHistory,
} from "./lib/state";

export interface Env {
  TELEGRAM_BOT_TOKEN: string;
  TELEGRAM_ALLOWED_CHAT_ID: string;
  ANTHROPIC_API_KEY: string;
  UPSTASH_REDIS_REST_URL: string;
  UPSTASH_REDIS_REST_TOKEN: string;
}

export default {
  // Runs on the cron schedule defined in wrangler.toml (every minute)
  async scheduled(_event: ScheduledEvent, env: Env): Promise<void> {
    const redisEnv = {
      UPSTASH_REDIS_REST_URL: env.UPSTASH_REDIS_REST_URL,
      UPSTASH_REDIS_REST_TOKEN: env.UPSTASH_REDIS_REST_TOKEN,
    };

    const lastOffset = await getLastOffset(redisEnv);
    const offset = lastOffset !== null ? lastOffset + 1 : undefined;

    const updates = await getUpdates(env.TELEGRAM_BOT_TOKEN, offset);
    if (updates.length === 0) return;

    const highestId = Math.max(...updates.map((u) => u.update_id));

    const messages = updates.filter(
      (u) =>
        u.message?.text &&
        String(u.message.chat.id) === env.TELEGRAM_ALLOWED_CHAT_ID
    );

    for (const update of messages) {
      const { chat, text } = update.message!;

      await sendTyping(env.TELEGRAM_BOT_TOKEN, chat.id);

      const history = await getHistory(redisEnv, chat.id);
      const reply = await generateResponse(env.ANTHROPIC_API_KEY, history, text!);

      await sendMessage(env.TELEGRAM_BOT_TOKEN, chat.id, reply);
      await appendHistory(redisEnv, chat.id, text!, reply);
    }

    await setLastOffset(redisEnv, highestId);
  },

  // Handles HTTP requests — keeps the Worker alive and gives a health check URL
  async fetch(_request: Request, _env: Env): Promise<Response> {
    return new Response("Standard Black EA Bot — running.", { status: 200 });
  },
};
